    int i1_capacity       = entries_per_block;
    int remaining         = total_blocks - DIRECT_BLOCKS - i1_capacity;
    int i2_l2_blocks      = (remaining + entries_per_block - 1) / entries_per_block;

    printf("Blocs totaux: %d\n", total_blocks);
    printf("Entrées par bloc indirect: %d\n", entries_per_block);
    printf("Blocs via I1: %d\n", i1_capacity);
    printf("Blocs restants après directs+I1: %d\n", remaining);
    printf("Blocs I2 niveau-2 nécessaires: %d\n", i2_l2_blocks);
    return 0;
}

